parameters.jsCode:
// Extract formId and URL from the AI Agent's output.
const output = $input.first().json.output || $input.first().json.text || '';
let formId = null;
let formUrl = null;
let shareUrl = null;

// Try to parse JSON from agent output
try {
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    formId = parsed.formId || parsed.smartFormId;
    formUrl = parsed.formUrl || parsed.url;
    shareUrl = parsed.shareUrl;
  }
} catch(e) {}

// Fix formUrl: ensure correct path
if (formUrl) {
  if (!formUrl.startsWith('http')) {
    formUrl = 'https://formfex.com/forms/response/' + formUrl;
  } else if (!formUrl.includes('/forms/response/')) {
    const slug = formUrl.split('/').pop();
    formUrl = 'https://formfex.com/forms/response/' + slug;
  }
}

// Fallback: extract UUID
if (!formId) {
  const uuidMatch = output.match(/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/i);
  if (uuidMatch) formId = uuidMatch[0];
}

// Fallback: extract URL
if (!formUrl) {
  const urlMatch = output.match(/https:\/\/formfex\.com\/forms\/response\/[\w-]+/);
  if (urlMatch) formUrl = urlMatch[0];
}

// Construct URL from shareUrl or formId
if (!formUrl && shareUrl) {
  formUrl = 'https://formfex.com/forms/response/' + shareUrl;
}
if (!formUrl && formId) {
  formUrl = 'https://formfex.com/forms/response/' + formId;
}

// Register for webhook monitoring
if (formId) {
  const staticData = $getWorkflowStaticData('global');
  const watchedFormIds = staticData.watchedFormIds ?? [];
  if (!watchedFormIds.includes(formId)) {
    watchedFormIds.push(formId);
    staticData.watchedFormIds = watchedFormIds;
  }
}

return [{ json: { formId, formUrl, output } }];

